  setBody('tasks', s.tasks.map(t => row(short(t.id), t.from + '\u2192' + t.to, pill(t.status))), 'tasks-count');
  setBody('audit', s.audit.map(a => row(short(a.at, 19), a.actor, a.action, a.target || '', pill(a.outcome))));
